-- Constant-time string comparison to prevent timing attacks
local function secure_compare(a, b)
    if type(a) ~= "string" or type(b) ~= "string" then
        return false
    end
    if #a ~= #b then
        return false
    end
    local result = 0
    for i = 1, #a do
        result = bit.bor(result, bit.bxor(string.byte(a, i), string.byte(b, i)))
    end
    return result == 0
end

-- Validate token format strictly (alphanumeric + hyphens only, fixed length range)
local function validate_token_format(token)
    if type(token) ~= "string" then
        return false
    end
    if #token < 32 or #token > 512 then
        return false
    end
    -- Only allow base64-safe characters and dots (for JWT-like tokens)
    if not ngx.re.match(token, "^[A-Za-z0-9_\\-\\.]+$", "jo") then
