end

-- Extract and validate the authentication token from the request
local function extract_auth_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil, "Missing Authorization header"
    end

    -- Strictly match "Bearer <token>" format
    local m = ngx.re.match(auth_header, "^Bearer\\s+(.+)$", "jo")
    if not m or not m[1] then
        return nil, "Invalid Authorization header format"
    end

    local token = m[1]
    if not validate_token_format(token) then
        return nil, "Invalid token format"
    end

    return token, nil
end

-- Verify token against a secure store (e.g., shared dict or upstream auth service)
-- In production, replace this with actual token verification (JWT validation, etc.)
local function verify_token(token)
    local shared_dict = ngx.shared.auth_tokens
    if not shared_dict then
        ngx.log(ngx.ERR, "auth_tokens shared dict not configured")
        return nil, "Internal server error"
    end

    local user_data_json = shared_dict:get(token)
    if not user_data_json then
        return nil, "Invalid or expired token"
    end

    local cjson = require("cjson.safe")
    local user_data, err = cjson.decode(user_data_json)
    if not user_data then
        ngx.log(ngx.ERR, "Failed to decode user data: ", err)
        return nil, "Internal server error"
    end

    -- Validate required fields exist
