    end

    -- Validate expiry
    if user_data.expires_at and user_data.expires_at < ngx.now() then
        shared_dict:delete(token)
        return nil, "Token expired"
    end

    return user_data, nil
end

-- Check if the URI is a public endpoint (exact match only)
local function is_public_endpoint(uri)
