-- Normalize and validate URI to prevent path traversal and bypass attacks
local function normalize_uri(raw_uri)
    if type(raw_uri) ~= "string" or #raw_uri == 0 then
        return nil
    end

    -- Reject URIs with null bytes
    if raw_uri:find("\0") then
        return nil
    end

    -- Reject URIs with path traversal attempts
    if ngx.re.match(raw_uri, "\\.\\.", "jo") then
        return nil
    end

    -- Reject URIs with encoded path separators that could bypass checks
    if ngx.re.match(raw_uri, "%2[fF]", "jo") then
        return nil
    end

    -- Normalize multiple slashes
    local normalized = ngx.re.gsub(raw_uri, "/+", "/", "jo")

    -- Remove trailing slash for consistent matching (except root)
    if #normalized > 1 and normalized:sub(-1) == "/" then
        normalized = normalized:sub(1, -2)
    end

    return normalized
end

-- Determine which protected prefix the URI falls under using exact prefix matching
-- Uses anchored prefix matching to prevent partial path bypass
-- e.g., "/admin" matches "/admin" and "/admin/users" but NOT "/administrator"
local function get_required_roles(uri)
    local matched_roles = nil
    local matched_prefix_len = 0

    for prefix, roles in pairs(ENDPOINT_ROLES) do
        -- Ensure the URI matches the prefix exactly as a path segment
        -- The URI must equal the prefix or have the prefix followed by "/"
        local is_match = false
        if uri == prefix then
            is_match = true
        elseif #uri > #prefix and uri:sub(1, #prefix) == prefix and uri:sub(#prefix + 1, #prefix + 1) == "/" then
            is_match = true
        end

        -- Use longest prefix match to handle overlapping routes
        if is_match and #prefix > matched_prefix_len then
            matched_roles = roles
            matched_prefix_len = #prefix
        end
    end

    return matched_roles
end

-- Check if a user role has the required permission
local function role_has_permission(user_role, required_permission)
    local permissions = ROLE_PERMISSIONS[user_role]
    if not permissions then
        return false
    end
    for _, perm in ipairs(permissions) do
        if perm == required_permission then
            return true
        end
    end
    return false
end

-- Check if user role is in the list of allowed roles
local function is_role_authorized(user_role, allowed_roles)
    if type(user_role) ~= "string" or type(allowed_roles) ~= "table" then
        return false
    end

    -- Validate that the role exists in our known roles
    if not ROLE_PERMISSIONS[user_role] then
        ngx.log(ngx.WARN, "Unknown role encountered: ", user_role)
        return false
    end

    for _, allowed_role in ipairs(allowed_roles) do
        if user_role == allowed_role then
            return true
        end
    end
    return false
end

